  })
  .map(item => {
    const raw = (item.json.title || '').trim();
    const colonIdx = raw.indexOf(':');
    let company = '', title = '';
    if (colonIdx > -1) {
      company = raw.substring(0, colonIdx).trim();
      title = raw.substring(colonIdx + 1).trim();
    } else {
      title = raw;
    }
    return { json: { title, company, url: item.json.link || '', source: 'WeWorkRemotely' } };
  });

