  '',
  'CANDIDATE PROFILE:',
  '- 10+ years QA experience, fintech and SaaS',
  '- Tools: Playwright, Cypress, Detox, Postman, SQL, Grafana, GitHub Actions',
  '- Domains: fintech, payments, digital banking, design tooling',
  '- Remote-worldwide only \u2014 no timezone restrictions stated by employer',
  '',
  'SCORING \u2014 score each job 1-3:',
  '3 = Strong match: senior/lead QA, SDET, automation engineer \u2014 fintech, SaaS, or payments domain \u2014 Playwright, Cypress, or Detox mentioned',
  '2 = Good match: QA engineer role, remote confirmed, any tech domain',
  '1 = Weak signal only: QA mentioned but role is junior, or domain is hardware/gaming/non-software',
  '',
  'RULE: Display ALL jobs regardless of score. Do not drop any job. Score 1 jobs are still shown.',
  '',
  'OUTPUT FORMAT (strict, WhatsApp 1600 char limit):',
  '\uD83D\uDFE2 Company \u00B7 Role \u00B7 stack hint \u00B7 URL',
  '\uD83D\uDFE1 Company \u00B7 Role \u00B7 URL',
  '\u26AA Company \u00B7 Role \u00B7 URL',
  '',
  'Final line:',
  'TODAY: X roles (Y\uD83D\uDFE2 Z\uD83D\uDFE1 W\u26AA) \u2014 from [' + count + '] new listings',
  '',
  'No preamble. No sign-off. List only.',
  '',
  'JOBS TO EVALUATE:',
  jobLines
].join('\n');

return [{ json: { prompt, count } }];

const response = $input.first().json;
const message = (response && response.content && response.content[0] && response.content[0].text || 'NO MATCHES TODAY').trim();
return [{ json: { message } }];

const response = $input.first().json;
const markdown = (response && response.data && response.data.markdown) || '';
const qaTerms = ['qa', 'quality', 'test', 'sdet', 'tester', 'automation'];
const jobs = [];
const seen = new Set();

const addJob = (title, url) => {
  const clean = title.replace(/^[#\-*>\s]+/, '').trim();
  if (!clean || !url || seen.has(url)) return;
  seen.add(url);
  jobs.push({ json: { title: clean, company: '', url, source: 'Remocate' } });
};

// Pass 1: markdown links where the link text itself contains a QA term
const linkRe = /\[([^\]]+)\]\((https?:\/\/[^\)\s]+)\)/g;
let m;
while ((m = linkRe.exec(markdown)) !== null) {
  if (qaTerms.some(t => m[1].toLowerCase().includes(t))) addJob(m[1], m[2]);
}

// Pass 2: paragraph blocks that mention a QA term — grab any URL in the same block
for (const block of markdown.split(/\n\n+/)) {
  if (!qaTerms.some(t => block.toLowerCase().includes(t))) continue;
  const lm = /\[([^\]]*)\]\((https?:\/\/[^\)\s]+)\)/.exec(block);
  const um = /https?:\/\/\S+/.exec(block);
  const rawUrl = lm ? lm[2] : (um ? um[0] : '');
  if (!rawUrl) continue;
  const url = rawUrl.replace(/[)\]>.,;]+$/, '');
  const titleLine = block.split('\n').find(l => qaTerms.some(t => l.toLowerCase().includes(t))) || '';
  const title = titleLine.replace(/\[[^\]]*\]\([^\)]*\)/g, '').replace(/^[#\-*>\s]+/, '').trim();
  if (title) addJob(title, url);
}

return jobs.length > 0 ? jobs : [{ json: { _empty: true } }];

