const items = $input.all();
const count = items.length;
const date = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
const esc = s => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const jobBlocks = items.map(item => {
  const j = item.json;
  const title = esc(j.title || 'Untitled');
  const company = j.company ? ' — ' + esc(j.company) : '';
  const source = ' — [' + esc(j.source || 'Unknown') + ']';
  const url = j.url ? '<br><a href=' + JSON.stringify(j.url) + '>' + esc(j.url) + '</a>' : '';
  return '<strong>' + title + '</strong>' + company + source + url;
}).join('<hr>');
const subject = 'QA Jobs Today — ' + date + ' (' + count + ' roles)';
const body = '<h3>📋 QA Jobs Today (' + count + ')</h3>' + jobBlocks;
return [{ json: { subject, body } }];
